SO(REC,VAL) ; EP - SEXUAL ORIENTATION - RETURNS SPECIFIC FIELD VALUES FOR RECORDS IN THE SEXUAL ORIENTATION FILE (#9999999.103)
 N RES S REC=$G(REC,""),VAL=$G(VAL,"E") Q:'$L(REC) ""
 ;S REC=$S(+REC=REC&$D(^AUTTSO(REC)):REC,$O(^AUTTSO("B",REC,0)):$O(^AUTTSO("B",REC,0)),$O(^AUTTSO("C",REC,0)):$O(^AUTTSO("C",REC,0)),1:"") Q:'REC ""  ;IHS/OIT/NKD AUT*98.1*33
 S REC=$S(+REC=REC&$D(^AUTTSO(REC)):REC,$O(^AUTTSO("B",REC,0)):$O(^AUTTSO("B",REC,0)),$O(^AUTTSO("C",REC,0)):$O(^AUTTSO("C",REC,0)),$O(^AUTTSO("C2",REC,0)):$O(^AUTTSO("C2",REC,0)),1:"") Q:'REC ""
 S RES=$G(^AUTTSO(REC,0))
 ;Q $S(VAL="E":$P(RES,U),VAL="C":$P(RES,U,2),VAL="S":$P(RES,U,3),1:REC)  ;IHS/OIT/NKD AUT*98.1*33
 Q $S(VAL="E":$P(RES,U),VAL="C":$P(RES,U,2),VAL="S":$P(RES,U,3),VAL="X":$P($G(^AUTTSO(REC,.8)),U),1:REC)
GI(REC,VAL) ; EP - GENDER IDENTITY - RETURNS SPECIFIC FIELD VALUES FOR RECORDS IN THE GENDER IDENTITY FILE (#9999999.104)
 N RES S REC=$G(REC,""),VAL=$G(VAL,"E") Q:'$L(REC) ""
 ;S REC=$S(+REC=REC&$D(^AUTTGI(REC)):REC,$O(^AUTTGI("B",REC,0)):$O(^AUTTGI("B",REC,0)),$O(^AUTTGI("C",REC,0)):$O(^AUTTGI("C",REC,0)),1:"") Q:'REC ""  ;IHS/OIT/NKD AUT*98.1*33
 S REC=$S(+REC=REC&$D(^AUTTGI(REC)):REC,$O(^AUTTGI("B",REC,0)):$O(^AUTTGI("B",REC,0)),$O(^AUTTGI("C",REC,0)):$O(^AUTTGI("C",REC,0)),$O(^AUTTGI("C2",REC,0)):$O(^AUTTGI("C2",REC,0)),1:"") Q:'REC ""
 S RES=$G(^AUTTGI(REC,0))
 ;Q $S(VAL="E":$P(RES,U),VAL="C":$P(RES,U,2),VAL="S":$P(RES,U,3),VAL="M":$P(RES,U,4),1:REC)  ;IHS/OIT/NKD AUT*98.1*33
 Q $S(VAL="E":$P(RES,U),VAL="C":$P(RES,U,2),VAL="S":$P(RES,U,3),VAL="M":$P(RES,U,4),VAL="X":$P($G(^AUTTGI(REC,.8)),U),1:REC)
PN(REC,VAL) ; EP - PRONOUNS - RETURNS SPECIFIC FIELD VALUES FOR RECORDS IN THE PRONOUNS FILE (#9999999.105)
 N RES S REC=$G(REC,""),VAL=$G(VAL,"E") Q:'$L(REC) ""
 ;S REC=$S(+REC=REC&$D(^AUTTPRN(REC)):REC,$O(^AUTTPRN("B",REC,0)):$O(^AUTTPRN("B",REC,0)),$O(^AUTTPRN("C",REC,0)):$O(^AUTTPRN("C",REC,0)),1:"") Q:'REC ""  ;IHS/OIT/NKD AUT*98.1*33
 S REC=$S(+REC=REC&$D(^AUTTPRN(REC)):REC,$O(^AUTTPRN("B",REC,0)):$O(^AUTTPRN("B",REC,0)),$O(^AUTTPRN("C",REC,0)):$O(^AUTTPRN("C",REC,0)),$O(^AUTTPRN("C2",REC,0)):$O(^AUTTPRN("C2",REC,0)),1:"") Q:'REC ""
 S RES=$G(^AUTTPRN(REC,0))
 ;Q $S(VAL="E":$P(RES,U),VAL="C":$P(RES,U,2),VAL="B":$$GET1^DIQ(9999999.105,REC,4),VAL="D":$$GET1^DIQ(9999999.105,REC,5),1:REC)  ;IHS/OIT/NKD AUT*98.1*33
 Q $S(VAL="E":$P(RES,U),VAL="C":$P(RES,U,2),VAL="B":$$GET1^DIQ(9999999.105,REC,4),VAL="D":$$GET1^DIQ(9999999.105,REC,5),VAL="X":$P($G(^AUTTPRN(REC,.8)),U),1:REC)
